// Check Availability v2 - Date + Nights approach with proper overlap detection
const input = $input.first().json;

const arrivalDate = input.arrivalDate;
const numNights = parseInt(input.numNights) || 1;
const numGuests = parseInt(input.numGuests) || 2;
const roomTypeId = input.roomTypeId;
const roomName = input.roomName;

// Calculate check-in and check-out
const checkIn = new Date(arrivalDate);
const checkOut = new Date(checkIn);
checkOut.setDate(checkOut.getDate() + numNights);

const checkInStr = checkIn.toISOString().split('T')[0];
const checkOutStr = checkOut.toISOString().split('T')[0];

// Return configuration for HTTP requests
return [{
  json: {
    arrivalDate: arrivalDate,
    numNights: numNights,
    numGuests: numGuests,
    roomTypeId: roomTypeId,
    roomName: roomName,
    checkIn: checkInStr,
    checkOut: checkOutStr,
    hotelId: input.hotelId
  }
}];

// Calculate availability using SEQUENTIAL execution - access cached results from previous nodes
// Using $('NodeName').first().json to get results from previously executed nodes

// Get data from cached node results
const roomTypesData = $('Get Room Types').first().json;
const roomInventoryData = $('Get Room Inventory').first().json;
const existingBookingsData = $('Get Existing Bookings').first().json;
const params = $('Prepare Availability v2').first().json;

// Extract arrays from responses
const roomTypes = roomTypesData?.room_types || [];
const roomInventory = roomInventoryData?.rooms || [];
const existingBookings = existingBookingsData?.bookings || [];

const checkIn = new Date(params.checkIn);
const checkOut = new Date(params.checkOut);
const numNights = params.numNights;
const numGuests = params.numGuests;
const requestedRoomTypeId = params.roomTypeId;
const roomName = params.roomName;

function calculateAvailability(roomTypeId) {
  // Find physical rooms of this type (id_product links to room type id)
  const roomsOfType = roomInventory.filter(r =>
    String(r.id_product) === String(roomTypeId)
  );

  if (roomsOfType.length === 0) return 0;

  let availableCount = 0;

  for (const room of roomsOfType) {
    const roomId = room.id;
    let isAvailable = true;

    // Check all existing bookings for this specific room
    for (const booking of existingBookings) {
      // Booking has id_room (physical room) and id_product (room type)
      const bookingRoomId = booking.id_room;

      if (String(bookingRoomId) !== String(roomId)) continue;

      // Parse booking dates
      const bookingDateFrom = new Date(booking.date_from);
      const bookingDateTo = new Date(booking.date_to);

      // Check for overlap: requested_start < existing_end AND requested_end > existing_start
      if (checkIn < bookingDateTo && checkOut > bookingDateFrom) {
        isAvailable = false;
        break;
      }
    }

    if (isAvailable) availableCount++;
  }

  return availableCount;
}

const availableRooms = [];

for (const roomType of Array.isArray(roomTypes) ? roomTypes : [roomTypes]) {
  if (!roomType || !roomType.id) continue;

  const rtId = roomType.id;
  const rtName = roomType.name || 'Habitación';
  const rtPrice = parseFloat(roomType.price) || 0;
  const rtCapacity = (parseInt(roomType.adults) || 2) + (parseInt(roomType.children) || 2);

  // Skip if specific room type requested and this isn't it
  if (requestedRoomTypeId && String(rtId) !== String(requestedRoomTypeId)) continue;

  // Skip if room capacity insufficient
  if (numGuests > rtCapacity) continue;

  const availableCount = calculateAvailability(rtId);

  if (availableCount > 0) {
    availableRooms.push({
      room_type_id: rtId,
      room_type_name: rtName,
      price_per_night: rtPrice,
      total_price: rtPrice * numNights,
      currency: 'COP',
      available_rooms: availableCount,
      max_guests: rtCapacity,
      check_in: params.checkIn,
      check_out: params.checkOut,
      num_nights: numNights
    });
  }
}

// Sort by price (lowest first)
availableRooms.sort((a, b) => a.price_per_night - b.price_per_night);

return [{
  json: {
    success: true,
    operation: 'check_availability_v2',
    arrival_date: params.arrivalDate,
    num_nights: numNights,
    check_in: params.checkIn,
    check_out: params.checkOut,
    num_guests: numGuests,
    room_name: roomName,
    available: availableRooms.length > 0,
    available_rooms: availableRooms,
    total_available_types: availableRooms.length
  }
}];

// Find alternative dates when no availability
const input = $input.first().json;

// Check if we have availability
const hasRooms = input.available === true && 
                 Array.isArray(input.available_rooms) && 
                 input.available_rooms.length > 0;

// If rooms available, just pass through
if (hasRooms) {
  return [{
    json: {
      ...input,
      hasAlternatives: false,
      message: "Hay disponibilidad"
    }
  }];
}

// No availability - need to find alternatives
const params = $('Prepare Availability v2').first().json;
const arrivalDate = new Date(params.arrivalDate);
const numNights = params.numNights;

const alternatives = [];

// Generate ±7 days alternatives
for (let offset = 1; offset <= 7 && alternatives.length < 6; offset++) {
  // Earlier date
  const earlier = new Date(arrivalDate);
  earlier.setDate(earlier.getDate() - offset);
  alternatives.push({
    type: 'earlier',
    arrival_date: earlier.toISOString().split('T')[0],
    num_nights: numNights,
    display: earlier.toLocaleDateString('es-CO', { 
      weekday: 'short', 
      day: 'numeric', 
      month: 'short' 
    })
  });

  // Later date
  const later = new Date(arrivalDate);
  later.setDate(later.getDate() + offset);
  alternatives.push({
    type: 'later',
    arrival_date: later.toISOString().split('T')[0],
    num_nights: numNights,
    display: later.toLocaleDateString('es-CO', { 
      weekday: 'short', 
      day: 'numeric', 
      month: 'short' 
    })
  });
}

// Sort by proximity to original date
alternatives.sort((a, b) => {
  const dateA = new Date(a.arrival_date);
  const dateB = new Date(b.arrival_date);
  const original = new Date(arrivalDate);
  return Math.abs(dateA - original) - Math.abs(dateB - original);
});

const bestAlternatives = alternatives.slice(0, 5);

// Format message for WhatsApp/Telegram
let message = `🏨 *Sin disponibilidad*\n\n`;
message += `No tenemos habitaciones para el *${arrivalDate.toLocaleDateString('es-CO', {
  weekday: 'long',
  day: 'numeric',
  month: 'long'
})}* por ${numNights} noches.\n\n`;
message += `*Alternativas disponibles:*\n\n`;

bestAlternatives.forEach((alt, idx) => {
  const emoji = alt.type === 'earlier' ? '⬅️' : '➡️';
  message += `${idx + 1}. ${emoji} ${alt.display}\n`;
});

message += `\n¿Te interesa alguna de estas fechas?`;

return [{
  json: {
    ...input,
    hasAlternatives: true,
    alternatives: bestAlternatives,
    user_message: message,
    original_date: arrivalDate.toISOString().split('T')[0],
    num_nights: numNights
  }
}];

// Generate booking link with room name
const input = $input.first().json;

// Room configuration mapping - configurable for new rooms
const ROOM_CONFIG = {
  '1': { name: 'Glamping Luna', slug: 'glamping-luna' },
  '2': { name: 'Glamping Colibri', slug: 'glamping-colibri' },
  '3': { name: 'Glamping Primavera', slug: 'glamping-primavera' },
  '4': { name: 'Glamping Corteza', slug: 'glamping-corteza' },
  // Aliases for name matching (lowercase, no accents)
  'luna': { id: '1', slug: 'glamping-luna', name: 'Glamping Luna' },
  'colibri': { id: '2', slug: 'glamping-colibri', name: 'Glamping Colibri' },
  'colibrí': { id: '2', slug: 'glamping-colibri', name: 'Glamping Colibri' },
  'primavera': { id: '3', slug: 'glamping-primavera', name: 'Glamping Primavera' },
  'corteza': { id: '4', slug: 'glamping-corteza', name: 'Glamping Corteza' }
};

const BASE_URL = 'http://143.198.21.142:8080/bamboo-glamping';

// Get room name from input
const roomName = input.room_name || '';
const checkIn = input.check_in || '';
const checkOut = input.check_out || '';
const availableRooms = input.available_rooms || [];

// Normalize room name for matching
const normalizedRoomName = roomName.toLowerCase()
  .replace(/glamping\s*/gi, '')
  .replace(/[áàäâ]/g, 'a')
  .replace(/[éèëê]/g, 'e')
  .replace(/[íìïî]/g, 'i')
  .replace(/[óòöô]/g, 'o')
  .replace(/[úùüû]/g, 'u')
  .trim();

// Find room in available rooms
let selectedRoom = null;
for (const room of availableRooms) {
  const availableName = room.room_type_name.toLowerCase()
    .replace(/glamping\s*/gi, '')
    .replace(/[áàäâ]/g, 'a')
    .replace(/[éèëê]/g, 'e')
    .replace(/[íìïî]/g, 'i')
    .replace(/[óòöô]/g, 'o')
    .replace(/[úùüû]/g, 'u')
    .trim();

  if (availableName === normalizedRoomName) {
    selectedRoom = room;
    break;
  }
}

// If not found in available rooms, return error
if (!selectedRoom) {
  const availableNames = availableRooms.map(r => r.room_type_name).join(', ');
  return [{
    json: {
      success: false,
      error: 'ROOM_NOT_AVAILABLE',
      message: `❌ La habitación "${roomName}" no está disponible para las fechas seleccionadas.\n\nHabitaciones disponibles: ${availableNames || 'Ninguna'}`,
      requested_room: roomName,
      available_rooms: availableRooms
    }
  }];
}

// Get room configuration
const roomId = String(selectedRoom.room_type_id);
const roomConfig = ROOM_CONFIG[roomId];

if (!roomConfig) {
  return [{
    json: {
      success: false,
      error: 'ROOM_NOT_CONFIGURED',
      message: `❌ Configuración no encontrada para la habitación ID ${roomId}. Contacte al administrador.`,
      room_id: roomId
    }
  }];
}

// Validate dates
if (!checkIn || !checkOut) {
  return [{
    json: {
      success: false,
      error: 'MISSING_DATES',
      message: '❌ Fechas de check-in/check-out no disponibles.',
      check_in: checkIn,
      check_out: checkOut
    }
  }];
}

// Build booking URL
const bookingUrl = `${BASE_URL}/${roomId}-${roomConfig.slug}.html?date_from=${checkIn}&date_to=${checkOut}`;

// Calculate nights if not provided
const checkInDate = new Date(checkIn);
const checkOutDate = new Date(checkOut);
const numNights = Math.round((checkOutDate - checkInDate) / (1000 * 60 * 60 * 24));

return [{
  json: {
    success: true,
    operation: 'generate_booking_link',
    booking_link: bookingUrl,
    room: {
      id: roomId,
      name: roomConfig.name,
      slug: roomConfig.slug,
      price_per_night: selectedRoom.price_per_night,
      total_price: selectedRoom.total_price,
      available_count: selectedRoom.available_rooms
    },
    dates: {
      check_in: checkIn,
      check_out: checkOut,
      num_nights: numNights
    },
    generated_at: new Date().toISOString()
  }
}];

// Format booking link response for user
const input = $input.first().json;

if (!input.success) {
  return [{
    json: {
      success: false,
      operation: 'booking_link_failed',
      message: input.message,
      error: input.error,
      timestamp: new Date().toISOString()
    }
  }];
}

const room = input.room;
const dates = input.dates;

const userMessage = 
  `✅ ¡Perfecto! Aquí está tu link de reserva\n\n` +
  `🏨 *${room.name}*\n` +
  `📅 Entrada: ${dates.check_in}\n` +
  `📅 Salida: ${dates.check_out}\n` +
  `🌙 Noches: ${dates.num_nights}\n` +
  `💰 Precio total: $${room.total_price?.toLocaleString('es-CO') || 'N/A'} COP\n\n` +
  `🔗 *Reserva aquí:*\n${input.booking_link}\n\n` +
  `Haz clic en el link para completar tu reserva en nuestro sitio web. ¡Te esperamos! 🌟`;

return [{
  json: {
    success: true,
    operation: 'booking_link_generated',
    booking_link: input.booking_link,
    room: room,
    dates: dates,
    message: userMessage,
    timestamp: new Date().toISOString()
  }
}];

// Format modify booking response
const response = $input.first().json;

return [{
  json: {
    success: true,
    operation: 'modify_booking',
    bookingId: $('Parse Input').first().json.bookingId,
    checkIn: $('Parse Input').first().json.checkIn,
    checkOut: $('Parse Input').first().json.checkOut,
    message: `Reserva ${$('Parse Input').first().json.bookingId} modificada exitosamente`,
    rawResponse: response
  }
}];

// Format cancel booking response
const response = $input.first().json;

return [{
  json: {
    success: true,
    operation: 'cancel_booking',
    bookingId: $('Parse Input').first().json.bookingId,
    message: `Reserva ${$('Parse Input').first().json.bookingId} cancelada exitosamente`,
    rawResponse: response
  }
}];
